export interface Mesa {
  id: number;
  numero: number;
}

export interface MenuItem {
  id: number;
  nombre: string;
  precio: number;
}

export interface Pedido {
  id: number;
  mesa: Mesa;
  items: MenuItem[];
  total: number;
  estado: string;
}

export type Producto = {
  id: number;
  nombre: string;
  categoria: string;
  precio: number;
};





// Mock service functions
export async function getPedidos(): Promise<Pedido[]> {
  return pedidos;
}

export async function agregarPedido(pedido: Pedido): Promise<void> {
  pedidos.push(pedido);
}

export async function eliminarPedido(id: number): Promise<void> {
  pedidos = pedidos.filter((p) => p.id !== id);
}

export async function getMenu(): Promise<Producto[]> {
  return productos; // Retorna datos mock en lugar de fetch
}

export async function agregarProducto(producto: Omit<Producto, "id">) {
  const nuevoProducto = { ...producto, id: Date.now() };
  productos.push(nuevoProducto);
  return nuevoProducto;
}

export async function eliminarProducto(id: number) {
  productos = productos.filter((p) => p.id !== id);
}

export async function editarProducto(
  id: number,
  producto: Omit<Producto, "id">
) {
  const index = productos.findIndex((p) => p.id === id);
  if (index !== -1) {
    productos[index] = { ...producto, id };
  }
}
